const item = $input.first().json;
const b = item.body || item;
const c = b.contato || {};
const q = b.questionario || {};

if (!c.nome || !c.email) {
  throw new Error('Campos obrigatorios ausentes: nome e email');
}

// Segmentacao (regras do spec F4 §6, prioridade top-down)
let segmento = 'Praticante Pessoal';
if (q.q6_ja_atendeu === 'sim_pago' || q.q5_objetivo === 'viver_de_reiki') {
  segmento = 'Terapeuta em Transicao';
} else if (
  ['profissional', 'viver_de_reiki'].includes(q.q5_objetivo) ||
  ['conseguir_pessoas', 'medo_cobrar', 'aspectos_legais'].includes(q.q4_maior_dificuldade)
) {
  segmento = 'Aspirante a Terapeuta';
}

const rotulos = {
  q1_momento_reiki: 'Momento no Reiki',
  q2_tempo_iniciacao: 'Tempo de iniciacao',
  q3_frequencia: 'Frequencia de pratica',
  q4_maior_dificuldade: 'Maior dificuldade',
  q5_objetivo: 'Objetivo principal',
  q6_ja_atendeu: 'Ja atendeu',
  q7_investimento: 'Investiria'
};
const linhas = Object.keys(rotulos)
  .map(k => `<li><b>${rotulos[k]}:</b> ${q[k] || '—'}</li>`)
  .join('');

const corpoNotificacao =
  `<h2>Novo lead — Lista de Espera</h2>` +
  `<p><b>Segmento:</b> ${segmento}</p>` +
  `<ul><li><b>Nome:</b> ${c.nome}</li>` +
  `<li><b>E-mail:</b> ${c.email}</li>` +
  `<li><b>WhatsApp:</b> ${c.whatsapp || '—'}</li></ul>` +
  `<h3>Questionario</h3><ul>${linhas}</ul>` +
  `<p style="color:#888">Origem: ${b.origem || 'landing-page'} · ${b.timestamp_cliente || ''}</p>`;

const primeiroNome = String(c.nome).split(' ')[0];
const corpoBoasVindas =
  `<p>Ola, ${primeiroNome}! 🌸</p>` +
  `<p>Voce entrou na lista de espera de <b>O Caminho do Reikiano Iniciante</b>. Que alegria ter voce aqui.</p>` +
  `<p>Em breve envio novidades sobre o programa completo. Enquanto isso, seu e-book ja e o primeiro passo do caminho.</p>` +
  `<p>Com carinho,<br>Mestre Renato Menezes<br><i>Om Reiki Om</i></p>`;

return [{
  json: {
    segmento,
    nome: c.nome,
    email: c.email,
    whatsapp: c.whatsapp || '',
    corpoNotificacao,
    corpoBoasVindas,
    assuntoNotificacao: `[LISTA-ESPERA] ${c.nome} · ${segmento}`
  }
}];
